INSERT INTO public.news_posts (id, category, date, title, source_label, source_url, summary, paragraphs) VALUES ('n1', 'Serviços', '2026-05-18', 'SIBiSC testa orientação digital para retirada de livros', 'Portal Oficial da Prefeitura de São Carlos', 'https://www.saocarlos.sp.gov.br/', 'A partir desta semana, usuários das bibliotecas de São Carlos podem consultar a disponibilidade e receber orientação de retirada diretamente no novo portal.', ARRAY['A Rede Municipal de Bibliotecas de São Carlos disponibiliza uma camada digital de consulta e orientação sobre o acervo. O sistema mostra a disponibilidade atualizada e direciona o usuário para a unidade indicada.', 'A iniciativa faz parte do programa de modernização da rede, que busca aproximar o acervo físico da rotina digital da população.', 'O prazo de empréstimo segue em 15 dias, com possibilidade de renovação conforme regras da unidade e disponibilidade do exemplar.']);
INSERT INTO public.news_posts (id, category, date, title, source_label, source_url, summary, paragraphs) VALUES ('n2', 'Acervo', '2026-05-14', 'Biblioteca Central recebe doacao de 3.000 volumes da USP', 'Assessoria SIBiSC', 'https://www.saocarlos.sp.gov.br/', 'O acervo técnico e científico amplia o acesso a obras de referência para estudantes e pesquisadores da cidade.', ARRAY['A Biblioteca Central recebeu uma nova coleção de livros técnicos, científicos e de referência por meio de parceria com a Universidade de São Paulo.', 'Os volumes contemplam areas como educacao, historia, sociologia, ciencias da informacao e saude publica.', 'A previsao do SIBiSC e concluir a catalogacao em etapas, priorizando as obras de maior demanda academica.']);
INSERT INTO public.news_posts (id, category, date, title, source_label, source_url, summary, paragraphs) VALUES ('n3', 'Eventos', '2026-05-11', 'Programacao cultural de junho 2026 e divulgada', 'Agenda Cultural SIBiSC', 'https://www.saocarlos.sp.gov.br/', 'Com o tema Ler e Resistir, o SIBiSC prepara atividades gratuitas para junho.', ARRAY['A agenda especial reunira rodas de leitura, oficinas para familias, encontros com autores e atividades voltadas a escolas publicas em junho.', 'As unidades da rede receberao acoes descentralizadas para aproximar a programacao cultural dos bairros.', 'A divulgação completa dos horários será feita no calendário oficial do novo web-app.']);
INSERT INTO public.news_posts (id, category, date, title, source_label, source_url, summary, paragraphs) VALUES ('n4', 'Inclusão', '2026-05-07', 'Projeto Leitura Digital capacita 200 idosos em São Carlos', 'Parceria SESC + SIBiSC', 'https://www.sescsp.org.br/', 'A parceria com o SESC formou novas turmas com foco em uso de e-readers, tablets e bibliotecas digitais.', ARRAY['O projeto de letramento digital voltado para idosos ampliou o numero de vagas e passou a atender novos bairros da cidade.', 'As aulas combinam uso de dispositivos móveis, navegação segura e acesso a conteúdos culturais e bibliográficos.', 'A proxima etapa preve turmas com foco em busca de informacao e uso do novo catalogo digital do SIBiSC.']);
INSERT INTO public.events (id, category, date, start_time, end_time, title, audience, location_name, location_address, signup, description) VALUES ('e1', 'Infantil', '2026-06-03', '14:00', '15:30', 'Hora do Conto Infantil', 'Crianças (4-8 anos)', 'Biblioteca Central', 'Rua Episcopal, 1415 - Centro', 'Entrada franca', 'Contação de histórias para crianças de 4 a 8 anos com a contadora Claudia Borges. Tema da semana: Os Bichos da Mata Atlântica.');
INSERT INTO public.events (id, category, date, start_time, end_time, title, audience, location_name, location_address, signup, description) VALUES ('e2', 'Educação', '2026-06-05', '18:30', '20:00', 'Letramento Digital para a Terceira Idade', 'Idosos (60+)', 'Biblioteca Vila Prado', 'Rua Bernardino de Campos, 980 - Vila Prado', '15 vagas', 'Aula gratuita sobre uso de tablets, e-readers e bibliotecas digitais. Os participantes podem levar seus dispositivos ou usar os equipamentos da biblioteca.');
INSERT INTO public.events (id, category, date, start_time, end_time, title, audience, location_name, location_address, signup, description) VALUES ('e3', 'Clube do Livro', '2026-06-09', '10:00', '11:30', 'Clube do Livro: Vidas Secas', 'Adultos', 'Biblioteca Central', 'Rua Episcopal, 1415 - Centro', 'Aberto ao público', 'Encontro mensal para discutir Vidas Secas, de Graciliano Ramos. Vale participar mesmo sem leitura completa.');
INSERT INTO public.events (id, category, date, start_time, end_time, title, audience, location_name, location_address, signup, description) VALUES ('e4', 'Educação', '2026-06-11', '14:00', '16:00', 'Workshop de Pesquisa Acadêmica', 'Estudantes universitários', 'BibCom UFSCar', 'Rodovia Washington Luis, km 235 - Monjolinho', 'Inscrição online', 'Oficina prática sobre bases científicas, normas ABNT e ferramentas de gestão bibliográfica.');
INSERT INTO public.events (id, category, date, start_time, end_time, title, audience, location_name, location_address, signup, description) VALUES ('e5', 'Lançamento', '2026-06-13', '19:00', '20:30', 'Lançamento: Memórias de São Carlos', 'Público geral', 'Biblioteca Central', 'Rua Episcopal, 1415 - Centro', 'Sem inscrição', 'Sessão de autógrafos e conversa com o historiador Paulo Bicudo sobre a memória cultural da cidade.');
INSERT INTO public.events (id, category, date, start_time, end_time, title, audience, location_name, location_address, signup, description) VALUES ('e6', 'Infantil', '2026-06-16', '14:00', '15:30', 'Oficina de Origami para Crianças', 'Crianças (6-12 anos)', 'Biblioteca Cidade Aracy', 'Avenida Regit Arab, 420 - Cidade Aracy', 'Vagas limitadas', 'Oficina de dobradura japonesa com materiais fornecidos pela biblioteca.');
INSERT INTO public.events (id, category, date, start_time, end_time, title, audience, location_name, location_address, signup, description) VALUES ('e7', 'Clube do Livro', '2026-06-18', '16:00', '17:30', 'Roda de Leitura: Poesia Brasileira', 'Adultos e jovens', 'Biblioteca Vila Prado', 'Rua Bernardino de Campos, 980 - Vila Prado', 'Entrada franca', 'Leitura coletiva e conversa sobre Drummond, Manuel Bandeira e Adélia Prado.');
